// Obtener la respuesta del agente de filtro
const respuestaAgente = $input.all()[0].json.respuesta || $input.all()[0].json.output || '';

// Normalizar la respuesta (limpiar espacios, saltos de línea y convertir a mayúsculas)
const respuestaNormalizada = respuestaAgente
  .toString()
  .trim()
  .toUpperCase()
  .replace(/\n/g, '')
  .replace(/\r/g, '');

// Determinar la decisión final
let decision;
let razonFallback = null;

// Verificar si la respuesta es válida
if (respuestaNormalizada.includes('IGNORAR')) {
  decision = 'IGNORAR';
} else if (respuestaNormalizada.includes('PROCESAR')) {
  decision = 'PROCESAR';
} else {
  // Si no es ninguna de las respuestas esperadas, usar fallback
  decision = 'PROCESAR';
  razonFallback = 'Respuesta del agente no válida o vacía. Aplicando fallback de seguridad.';

  // Registrar para debugging
  console.log('⚠️ FALLBACK ACTIVADO');
  console.log('Respuesta original:', respuestaAgente);
  console.log('Respuesta normalizada:', respuestaNormalizada);
}

// Preparar el output
const resultado = {
  decision: decision,
  respuesta_agente_original: respuestaAgente,
  fallback_aplicado: razonFallback !== null,
  razon_fallback: razonFallback,
  timestamp: new Date().toISOString()
};

// Log para monitoreo
if (decision === 'IGNORAR') {
  console.log('🚫 Mensaje filtrado como IGNORAR');
} else {
  console.log('✅ Mensaje procesado como PROCESAR');
  if (razonFallback) {
    console.log('⚠️ Razón:', razonFallback);
  }
}

// Retornar el resultado
return resultado;

// Función para normalizar números de teléfono mexicanos en n8n
// Usar en un nodo "Code" o "Function"

function normalizePhone(phoneNumber) {
    // Si el número es null, undefined o vacío, retornarlo tal como está
    if (!phoneNumber || phoneNumber === '') {
        return phoneNumber;
    }

    // Convertir a string y limpiar: quitar espacios, guiones, paréntesis, etc.
    let cleanPhone = phoneNumber.toString().replace(/[^0-9+]/g, '');

    // Casos para números mexicanos (+52)

    // Patrón: +521XXXXXXXXXX -> +52XXXXXXXXXX (remover el 1 después de +52)
    if (/^\+521[0-9]{10}$/.test(cleanPhone)) {
        return '+52' + cleanPhone.substring(4);
    }

    // Patrón: 521XXXXXXXXXX -> +52XXXXXXXXXX (sin +, con 1)
    if (/^521[0-9]{10}$/.test(cleanPhone)) {
        return '+52' + cleanPhone.substring(3);
    }

    // Patrón: +52XXXXXXXXXX -> ya está correcto
    if (/^\+52[0-9]{10}$/.test(cleanPhone)) {
        return cleanPhone;
    }

    // Patrón: 52XXXXXXXXXX -> +52XXXXXXXXXX (agregar +)
    if (/^52[0-9]{10}$/.test(cleanPhone)) {
        return '+' + cleanPhone;
    }

    // Patrón: 1XXXXXXXXXX (11 dígitos empezando con 1) -> +52XXXXXXXXXX
    if (/^1[0-9]{10}$/.test(cleanPhone)) {
        return '+52' + cleanPhone.substring(1);
    }

    // Patrón: XXXXXXXXXX (10 dígitos) -> +52XXXXXXXXXX (asumir México)
    if (/^[0-9]{10}$/.test(cleanPhone)) {
        return '+52' + cleanPhone;
    }

    // Si no coincide con ningún patrón conocido, retornar original
    return phoneNumber;
}

// Código adaptado para tu estructura específica
const phoneFromWebhook = $input.first().json.phone_number;
const normalizedPhone = normalizePhone(phoneFromWebhook);

return [{
    json: {
        ...$input.first().json,  // Mantiene todos los datos originales del webhook
        phone_number_normalized: normalizedPhone,
        was_normalized: phoneFromWebhook !== normalizedPhone,
        original_phone_number: phoneFromWebhook
    }
}];
